import{_ as a,o as t,c as e,a4 as i}from"./chunks/framework.BDOgl-CJ.js";const c=JSON.parse('{"title":"Clash Verge 代理模式与内网直连配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"artifacts/clash_proxy_modes_guide.md","filePath":"artifacts/clash_proxy_modes_guide.md","lastUpdated":1777290866000}'),l={name:"artifacts/clash_proxy_modes_guide.md"};function n(h,s,r,o,p,d){return t(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="clash-verge-代理模式与内网直连配置指南" tabindex="-1">Clash Verge 代理模式与内网直连配置指南 <a class="header-anchor" href="#clash-verge-代理模式与内网直连配置指南" aria-label="Permalink to &quot;Clash Verge 代理模式与内网直连配置指南&quot;">​</a></h1><p>在访问公司内网资源（如 <code>10.17.0.22</code>）时，根据 Clash Verge 运行模式的不同，需要采取不同的直连方案。以下是两种情况的详细说明。</p><hr><h2 id="模式一-tun-模式-强制网卡接管" tabindex="-1">模式一：TUN 模式 (强制网卡接管) <a class="header-anchor" href="#模式一-tun-模式-强制网卡接管" aria-label="Permalink to &quot;模式一：TUN 模式 (强制网卡接管)&quot;">​</a></h2><h3 id="_1-原理与流程图" tabindex="-1">1. 原理与流程图 <a class="header-anchor" href="#_1-原理与流程图" aria-label="Permalink to &quot;1. 原理与流程图&quot;">​</a></h3><p>Clash 创建一个虚拟网卡（utun），接管系统<strong>网络层 (L3)</strong> 的所有流量。无论应用本身是否支持代理，所有数据包在离开物理网卡前都会被强制拦截并交给 Clash 引擎。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App[应用程序] --&gt;|发起请求| Stack[系统网络协议栈]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stack --&gt;|流量拦截| TUN[TUN 虚拟网卡]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TUN --&gt;|解析包内容| Clash{Clash 引擎}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Clash --&gt;|匹配 Merge.yaml 规则| Rule{直连规则?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Rule --&gt;|10.0.0.0/8| Direct[✅ 直连内网设备]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Rule --&gt;|其他| Proxy[🚀 代理服务器]</span></span></code></pre></div><h3 id="_2-解决方案-修改-clash-内部规则" tabindex="-1">2. 解决方案：修改 Clash 内部规则 <a class="header-anchor" href="#_2-解决方案-修改-clash-内部规则" aria-label="Permalink to &quot;2. 解决方案：修改 Clash 内部规则&quot;">​</a></h3><p>在这种模式下，内网流量能否直连，完全取决于 Clash 的 <strong>Merge 规则</strong>。</p><ul><li><strong>配置文件路径</strong>: <code>~/Library/Application Support/io.github.clash-verge-rev.clash-verge-rev/profiles/Merge.yaml</code></li><li><strong>关键配置项</strong>: <code>prepend-rules</code></li><li><strong>代码示例</strong>:<div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">prepend-rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DOMAIN,gitlab.anyverse.work,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,10.0.0.0/8,DIRECT,no-resolve</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 核心规则：将10网段设为直连</span></span></code></pre></div></li></ul><h3 id="_3-特点" tabindex="-1">3. 特点 <a class="header-anchor" href="#_3-特点" aria-label="Permalink to &quot;3. 特点&quot;">​</a></h3><ul><li><strong>优点</strong>: 覆盖范围最广，不支持代理设置的应用（如终端、旧软件）也能生效。</li><li><strong>缺点</strong>: 如果 Clash 规则没写好，会导致内网也去绕远路走代理，甚至完全断连。</li></ul><hr><h2 id="模式二-系统代理模式-应用层转发" tabindex="-1">模式二：系统代理模式 (应用层转发) <a class="header-anchor" href="#模式二-系统代理模式-应用层转发" aria-label="Permalink to &quot;模式二：系统代理模式 (应用层转发)&quot;">​</a></h2><h3 id="_1-原理与流程图-1" tabindex="-1">1. 原理与流程图 <a class="header-anchor" href="#_1-原理与流程图-1" aria-label="Permalink to &quot;1. 原理与流程图&quot;">​</a></h3><p>Clash 仅在本地监听端口（如 <code>7897</code>）。应用（如 Chrome）在发起请求前，会先读取系统的“忽略代理列表”。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    App[应用程序] --&gt;|准备请求| Bypass{匹配系统忽略列表?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Bypass --&gt;|是: 10.17.x.x| Direct[✅ 直接发出 / 绕过代理]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Bypass --&gt;|否| ProxyPort[发送至 127.0.0.1:7897]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ProxyPort --&gt; Clash{Clash 引擎}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Clash --&gt;|根据内核规则| Out[🚀 代理服务器]</span></span></code></pre></div><p>应用在发送请求前，会先查看系统的 <strong>“忽略代理列表”</strong>。</p><h3 id="_2-解决方案-修改-macos-系统设置" tabindex="-1">2. 解决方案：修改 macOS 系统设置 <a class="header-anchor" href="#_2-解决方案-修改-macos-系统设置" aria-label="Permalink to &quot;2. 解决方案：修改 macOS 系统设置&quot;">​</a></h3><p>在这种模式下，为了保证内网访问不进 Clash，需要在 macOS 系统层进行排除。</p><ul><li><strong>配置路径</strong>: <code>系统设置</code> -&gt; <code>网络</code> -&gt; <code>Wi-Fi (或以太网)</code> -&gt; <code>详细信息</code> -&gt; <code>代理</code></li><li><strong>关键配置项</strong>: <code>忽略这些主机与域的代理设置</code> (Bypass)</li><li><strong>配置内容</strong>:<div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.*, 172.16.*, 192.168.*, *.anyverse.work, localhost, 127.0.0.1</span></span></code></pre></div></li></ul><h3 id="_3-特点-1" tabindex="-1">3. 特点 <a class="header-anchor" href="#_3-特点-1" aria-label="Permalink to &quot;3. 特点&quot;">​</a></h3><ul><li><strong>优点</strong>: 性能消耗极低，内网流量完全不经过 Clash 进程，稳定性最高。</li><li><strong>缺点</strong>: 部分不遵循系统代理设置的应用（如某些命令行工具）可能仍会走默认网卡导致无法上网。</li></ul><hr><h2 id="总结与对比" tabindex="-1">总结与对比 <a class="header-anchor" href="#总结与对比" aria-label="Permalink to &quot;总结与对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">TUN 模式</th><th style="text-align:left;">系统代理模式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工作层面</strong></td><td style="text-align:left;">网络层 (虚拟网卡)</td><td style="text-align:left;">应用层 (HTTP/SOCKS)</td></tr><tr><td style="text-align:left;"><strong>直连靠谁</strong></td><td style="text-align:left;"><strong>Clash 内部规则</strong></td><td style="text-align:left;"><strong>macOS 系统设置</strong></td></tr><tr><td style="text-align:left;"><strong>内网表现</strong></td><td style="text-align:left;">由 Clash 决定转发</td><td style="text-align:left;">由 macOS 决定是否发给 Clash</td></tr><tr><td style="text-align:left;"><strong>首选建议</strong></td><td style="text-align:left;">适合需要全局代理、处理特殊协议时</td><td style="text-align:left;">适合大多数 Web 开发场景，更稳定</td></tr></tbody></table><hr><h2 id="验证方法-terminal" tabindex="-1">验证方法 (Terminal) <a class="header-anchor" href="#验证方法-terminal" aria-label="Permalink to &quot;验证方法 (Terminal)&quot;">​</a></h2><p>无论哪种模式，你都可以运行以下命令测试：</p><ol><li><strong>测试绕过代理直连</strong>:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --noproxy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;*&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://10.17.0.22:8080</span></span></code></pre></div></li><li><strong>查看 Clash 实时生效规则</strong>:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --unix-socket</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/verge/verge-mihomo.sock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost/rules</span></span></code></pre></div></li></ol><hr><p>维护者: 基座模型组</p>`,32)])])}const k=a(l,[["render",n]]);export{c as __pageData,k as default};
